    74→function ScanningAnimation({ type, success, error }: { type: BiometricType; success?: boolean; error?: boolean }) {
    75→  const color = error ? "red" : success ? "green" : type === "face" ? "sky" : "violet";
    76→  const colorMap: Record<string, { ring: string; icon: string; glow: string }> = {
    77→    violet: { ring: "border-violet-500", icon: "text-violet-400", glow: "bg-violet-500/20" },
    78→    sky:    { ring: "border-sky-400",    icon: "text-sky-400",    glow: "bg-sky-500/20"    },
    79→    green:  { ring: "border-green-400",  icon: "text-green-400",  glow: "bg-green-500/20"  },
    80→    red:    { ring: "border-red-400",    icon: "text-red-400",    glow: "bg-red-500/20"    },
    81→  };
    82→  const c = colorMap[color];
    83→  const Icon = error ? AlertCircle : success ? CheckCircle2 : type === "face" ? ScanFace : Fingerprint;
    84→
    85→  return (
    86→    <div className="relative flex items-center justify-center w-48 h-48 mx-auto">
    87→      {!success && !error && [0, 1, 2].map(i => (
    88→        <motion.div
    89→          key={i}
    90→          className={`absolute rounded-full border ${c.ring}`}
    91→          initial={{ width: 80, height: 80, opacity: 0.7 }}
    92→          animate={{ width: 80 + (i + 1) * 34, height: 80 + (i + 1) * 34, opacity: 0 }}
    93→          transition={{ duration: 2.2, repeat: Infinity, delay: i * 0.55, ease: "easeOut" }}
    94→        />
    95→      ))}
    96→      {(success || error) && (
    97→        <motion.div
    98→          className={`absolute rounded-full border-2 ${c.ring}`}
    99→          initial={{ width: 80, height: 80, opacity: 1 }}
   100→          animate={{ width: 160, height: 160, opacity: 0 }}
   101→          transition={{ duration: 0.8, ease: "easeOut" }}
   102→        />
   103→      )}
   104→      <motion.div
   105→        className={`relative z-10 p-6 rounded-full ${c.glow}`}
   106→        animate={success || error ? { scale: [1, 1.15, 1] } : { scale: [1, 1.04, 1] }}
   107→        transition={{ duration: success || error ? 0.4 : 2, repeat: success || error ? 0 : Infinity }}
   108→      >
   109→        <Icon className={`w-12 h-12 ${c.icon}`} />
   110→      </motion.div>
   111→    </div>
   112→  );
   113→}
