register(userData, {
  onSuccess: (user: any) => {
    queryClient.setQueryData(["/api/user"], user);
    if (user.resent) {
      toast({
        title: "حسابك موجود — تم إعادة إرسال الرمز",
        description: "يوجد حساب غير مفعّل بهذه البيانات. أرسلنا رمزًا جديدًا إلى بريدك.",
      });
    }
    // For client accounts — show face setup step first
